const trigger = $('When Executed by Another Workflow').first().json;
const nuevosItemsStr = trigger.nuevos_items;
const pedido = $('Buscar Pedido Original').first().json;
const inventario = $input.all().map(i => i.json);

const estadoValido = pedido.Estado === 'Activo' || pedido.Estado === 'Modificado';
if (!pedido.ID_Pedido || !estadoValido) {
  return [{ json: { error: 'si', mensaje: 'Pedido no encontrado o ya no se puede modificar (estado: ' + (pedido.Estado || 'desconocido') + '). Usa lookup_order primero para obtener el ID.' } }];
}

const normalize = (s) => (s||'').toLowerCase().trim().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const findProd = (nombre) => inventario.find(p => {
  const n = normalize(p.Nombre);
  const q = normalize(nombre);
  return n === q || n.includes(q) || q.includes(n);
});

const itemsOriginales = pedido.Productos.split(';').map(item => {
  const p = item.split(':');
  const cantStr = p[1].trim();
  return { nombre: p[0].trim(), cantidad: parseFloat(cantStr), unidad: cantStr.includes('ud') ? 'unidad' : 'kg' };
});

const stockVirtual = {};
const itemsRestaurar = [];
for (const item of itemsOriginales) {
  const prod = findProd(item.nombre);
  if (prod) {
    const restored = Math.round((parseFloat(prod.Stock_Disponible) + item.cantidad) * 100) / 100;
    stockVirtual[prod.ID_Producto] = restored;
    itemsRestaurar.push({ id_producto: prod.ID_Producto, Stock_Disponible: restored });
  }
}

const nuevosItems = nuevosItemsStr.split(',').map(item => {
  const p = item.trim().split(':');
  return { nombre: p[0].trim(), cantidad: parseFloat(p[1]), unidad: (p[2]||'kg').trim().toLowerCase() };
});

let errores = [], nuevasLineas = [], total = 0;
for (const item of nuevosItems) {
  const prod = findProd(item.nombre);
  if (!prod) { errores.push(`"${item.nombre}" no encontrado en el inventario`); continue; }
  if (prod.Unidad_Medida === 'unidad' && !Number.isInteger(item.cantidad)) { errores.push(`"${item.nombre}" requiere unidades enteras`); continue; }
  const stockDisp = stockVirtual[prod.ID_Producto] !== undefined ? stockVirtual[prod.ID_Producto] : parseFloat(prod.Stock_Disponible);
  if (stockDisp < item.cantidad) { errores.push(`Stock insuficiente de "${item.nombre}": disponible ${stockDisp} ${prod.Unidad_Medida}`); continue; }
  const precio = parseFloat(prod.Precio_Unitario);
  const subtotal = Math.round(item.cantidad * precio * 100) / 100;
  total += subtotal;
  nuevasLineas.push({ nombre: prod.Nombre, cantidad: item.cantidad, unidad: prod.Unidad_Medida, precio_unitario: precio, subtotal, id_producto: prod.ID_Producto, stock_nuevo: Math.round((stockDisp - item.cantidad) * 100) / 100 });
}

if (errores.length > 0) {
  return [{ json: { error: 'si', mensaje: 'No se pudo modificar: ' + errores.join('. ') } }];
}

const productosTexto = nuevasLineas.map(l => `${l.nombre}:${l.cantidad}${l.unidad==='kg'?'kg':'ud'}:${l.subtotal.toFixed(2)}€`).join(';');
const desglose = nuevasLineas.map(l => `• ${l.nombre}: ${l.cantidad} ${l.unidad} × ${l.precio_unitario.toFixed(2)}€ = ${l.subtotal.toFixed(2)}€`).join('\n');
const totalR = Math.round(total * 100) / 100;

return [{ json: {
  error: 'no',
  id_pedido: pedido.ID_Pedido,
  nombre_cliente: pedido.Nombre_Cliente,
  telefono: pedido.Telefono,
  fecha_modificacion: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' }),
  items_restaurar: itemsRestaurar,
  nuevas_lineas: nuevasLineas,
  productos_texto: productosTexto,
  desglose,
  total: totalR
}}];

